from flask import Flask, request, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, UserMixin, login_user, logout_user, current_user
from flask_mfa.totp import TOTP

app = Flask(__name__)
app.config["SQLALCHEMY_DATABASE_URI"] = "sqlite:///users.db"
db = SQLAlchemy(app)
login_manager = LoginManager()
login_manager.init_app(app)
totp = TOTP()

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(100), unique=True)
    password = db.Column(db.String(100))
    secret = db.Column(db.String(100))

@login_manager.user_loader
def load_user(username):
    return User.query.get(username)

@app.route("/login", methods=["POST"])
def login():
    username = request.form["username"]
    password = request.form["password"]
    user = User.query.filter_by(username=username).first()
    if user and totp.verify_totp(user.secret, request.form["code"]):
        login_user(user)
        return redirect(url_for("protected_resource"))
    return "Invalid credentials", 401

@app.route("/verify-mfa")
def verify_mfa():
    user = current_user
    code = request.args.get("code")
    if totp.verify_totp(user.secret, code):
        return "Verified", 200
    return "Invalid code", 401

@app.route("/protected-resource")
def protected_resource():
    if not current_user.is_authenticated:
        return redirect(url_for("login"))
    return "Protected Resource"

if __name__ == "__main__":
    app.run(debug=True)